#include <stdio.h>
#include <string.h>

int digitDist(char a, char b) {
    int x = a - '0';
    int y = b - '0';
    int diff = x > y ? x - y : y - x;
    return diff < 10 - diff ? diff : 10 - diff;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        static char S[100005];
        static char K[15];
        scanf("%s", S);
        scanf("%s", K);
        int best = 1e9;
        for (int i = 0; i <= N - M; ++i) {
            int cur = 0;
            for (int j = 0; j < M; ++j) {
                cur += digitDist(S[i + j], K[j]);
            }
            if (cur < best) best = cur;
        }
        printf("%d\n", best);
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;

inline int digitDist(char a, char b) {
    int x = a - '0';
    int y = b - '0';
    int diff = abs(x - y);
    return min(diff, 10 - diff);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int N, M; cin >> N >> M;
        string S, K; cin >> S >> K;
        int best = INT_MAX;
        for (int i = 0; i <= N - M; ++i) {
            int cur = 0;
            for (int j = 0; j < M; ++j) cur += digitDist(S[i + j], K[j]);
            best = min(best, cur);
        }
        cout << best << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static int digitDist(char a, char b) {
        int x = a - '0';
        int y = b - '0';
        int diff = Math.abs(x - y);
        return Math.min(diff, 10 - diff);
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            String S = br.readLine().trim();
            String K = br.readLine().trim();
            int best = Integer.MAX_VALUE;
            for (int i = 0; i <= N - M; ++i) {
                int cur = 0;
                for (int j = 0; j < M; ++j) {
                    cur += digitDist(S.charAt(i + j), K.charAt(j));
                }
                if (cur < best) best = cur;
            }
            sb.append(best).append('\n');
        }
        System.out.print(sb.toString());
    }
}

